const $=(s,r=document)=>r.querySelector(s), $$=(s,r=document)=>[...r.querySelectorAll(s)];
const A='/api/admin', M='/api/media';
const app={admin:null,module:'dashboard',settings:null,cache:{},activation:null};
const MODULES=[
 ['Principal',[['dashboard','⌂','Dashboard'],['visual','◉','Editor Visual'],['products','□','Produtos'],['categories','▦','Categorias'],['orders','▤','Pedidos'],['customers','♙','Clientes']]],
 ['Comercial',[['marketing','◎','Marketing'],['drops','◷','Drops'],['outfits','✦','Outfits'],['inventory','▥','Estoque'],['suppliers','▱','Fornecedores'],['media','▧','Mídias']]],
 ['Gestão',[['pages','≡','Páginas'],['reports','↗','Relatórios'],['integrations','⇄','Integrações'],['settings','⚙','Configurações'],['admins','♜','Administradores'],['audit','☷','Auditoria']]]
];
const RESOURCE_MAP={
 categories:{title:'Categorias',type:'categories',fields:[['name','Nome','text'],['slug','URL/slug','text'],['description','Descrição','textarea'],['image','Imagem','text'],['parent','Categoria principal','text'],['active','Ativa','checkbox'],['seoTitle','Título SEO','text'],['seoDescription','Descrição SEO','textarea']]},
 customers:{title:'Clientes',type:'customers',fields:[['name','Nome','text'],['email','E-mail','email'],['phone','Telefone','text'],['cpf','CPF','text'],['tags','Tags (separadas por vírgula)','tags'],['segment','Segmento','text'],['cashback','Cashback','number'],['points','Pontos','number'],['blocked','Bloqueado','checkbox'],['notes','Observações','textarea']]},
 drops:{title:'Drops',type:'drops',fields:[['name','Nome do drop','text'],['description','Descrição','textarea'],['image','Imagem de capa','text'],['date','Data','datetime-local'],['status','Status','select:draft,published,scheduled,closed'],['productIds','IDs dos produtos','tags'],['waitingList','Lista de espera ativa','checkbox'],['counter','Contador ativo','checkbox']]},
 outfits:{title:'Outfits / Lookbook',type:'outfits',fields:[['name','Nome','text'],['description','Descrição','textarea'],['image','Imagem flat lay','text'],['status','Status','select:draft,published'],['productIds','Produtos vinculados','tags'],['hotspots','Hotspots (JSON)','json']]},
 suppliers:{title:'Fornecedores',type:'suppliers',fields:[['name','Nome','text'],['document','Documento','text'],['contact','Contato','text'],['email','E-mail','email'],['phone','Telefone','text'],['leadTime','Prazo médio (dias)','number'],['notes','Observações','textarea'],['active','Ativo','checkbox']]},
 pages:{title:'Páginas',type:'pages',fields:[['title','Título','text'],['slug','URL/slug','text'],['status','Status','select:draft,published,scheduled'],['content','Conteúdo','textarea'],['seoTitle','Título SEO','text'],['seoDescription','Descrição SEO','textarea'],['scheduledAt','Agendar publicação','datetime-local']]},
 campaigns:{title:'Campanhas',type:'campaigns',fields:[['name','Nome','text'],['channel','Canal','select:banner,popup,email,whatsapp,push'],['status','Status','select:draft,active,scheduled,finished'],['title','Título','text'],['message','Mensagem','textarea'],['image','Imagem','text'],['link','Link','text'],['startsAt','Início','datetime-local'],['endsAt','Fim','datetime-local'],['segment','Segmento','text']]},
 coupons:{title:'Cupons',type:'coupons',fields:[['code','Código','text'],['type','Tipo','select:percent,fixed'],['value','Valor','number'],['minimum','Pedido mínimo','number'],['usageLimit','Limite de uso','number'],['active','Ativo','checkbox'],['expiresAt','Validade','datetime-local'],['eligibleProducts','Produtos elegíveis','tags'],['eligibleCategories','Categorias elegíveis','tags']]},
 testimonials:{title:'Depoimentos',type:'testimonials',fields:[['name','Nome','text'],['text','Depoimento','textarea'],['rating','Avaliação','number'],['image','Imagem','text'],['status','Status','select:draft,published,hidden']]},
 reviews:{title:'Avaliações',type:'reviews',fields:[['productId','ID do produto','text'],['customerName','Cliente','text'],['rating','Nota','number'],['text','Avaliação','textarea'],['status','Status','select:pending,published,hidden'],['reply','Resposta da loja','textarea']]},
 shipping:{title:'Regras de frete',type:'shipping',fields:[['name','Nome da regra','text'],['type','Tipo','select:default,cep,state,weight,product,free'],['region','Região/CEP/Estado','text'],['value','Valor','number'],['deadline','Prazo em dias','number'],['minimum','Valor mínimo','number'],['active','Ativa','checkbox']]},
 payments:{title:'Formas de pagamento',type:'payments',fields:[['name','Nome','text'],['type','Tipo','select:pix,whatsapp,card,other'],['icon','Ícone/imagem','text'],['instructions','Instruções','textarea'],['active','Ativa','checkbox'],['order','Ordem','number']]},
 integrations:{title:'Integrações',type:'integrations',fields:[['name','Nome','text'],['provider','Provedor','text'],['category','Categoria','select:payment,shipping,analytics,marketing,fiscal,crm,webhook'],['enabled','Ativa','checkbox'],['publicConfig','Configuração pública (JSON)','json'],['notes','Observações','textarea']]}
};
function esc(v=''){return String(v).replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]))}
function money(v){return new Intl.NumberFormat('pt-BR',{style:'currency',currency:'BRL'}).format(Number(v)||0)}
function toast(msg){const e=$('#adminToast');e.textContent=msg;e.classList.add('show');clearTimeout(toast.t);toast.t=setTimeout(()=>e.classList.remove('show'),2800)}
function busy(on=true){let e=$('.loading-line');if(on&&!e){document.body.insertAdjacentHTML('beforeend','<div class="loading-line"></div>')}if(!on&&e)e.remove()}
async function api(action,opt={}){busy();try{const url=`${A}?action=${encodeURIComponent(action)}${opt.query?`&${new URLSearchParams(opt.query)}`:''}`;const res=await fetch(url,{method:opt.method||'GET',headers:opt.body?{'content-type':'application/json'}:{},body:opt.body?JSON.stringify(opt.body):undefined,cache:'no-store'});const j=await res.json();if(!j.ok)throw Object.assign(new Error(j.error||'Erro'),{status:res.status,details:j.details});return j}finally{busy(false)}}
async function boot(){try{const st=await api('status');if(!st.activated)return renderActivation();try{const me=await api('me');app.admin=me.admin;renderShell()}catch{renderLogin()}}catch(e){$('#adminApp').innerHTML=`<div class="auth-shell"><div class="auth-card"><div class="auth-logo">ICANT</div><h1>Falha ao abrir o painel</h1><p>${esc(e.message)}</p><button class="btn" onclick="location.reload()">Tentar novamente</button></div></div>`}}
function renderActivation(){app.activation=null;$('#adminApp').innerHTML=`<div class="auth-shell"><form class="auth-card" id="activateForm"><div class="auth-logo">ICANT</div><div class="auth-hint">Primeira ativação. O código funciona uma única vez. Depois, o acesso exige senha e autenticação em dois fatores.</div><h1>Ativar Painel Master</h1><div class="field"><label>Nome do administrador</label><input name="name" value="Brian Gabriel Freitas Soares" required></div><div class="field"><label>E-mail autorizado</label><input type="email" name="email" value="briangabrielfsoares@gmail.com" required></div><div class="field"><label>Código de ativação</label><input name="code" required></div><div class="field"><label>Crie uma senha forte</label><input type="password" name="password" minlength="10" required></div><button class="btn" style="width:100%">CONTINUAR E CONFIGURAR 2FA</button></form></div>`;$('#activateForm').onsubmit=async e=>{e.preventDefault();const b=Object.fromEntries(new FormData(e.target));try{const j=await api('activate-start',{method:'POST',body:b});app.activation=j;renderActivation2()}catch(err){toast(err.message)}}}
function renderActivation2(){$('#adminApp').innerHTML=`<div class="auth-shell"><form class="auth-card" id="finishForm"><div class="auth-logo">ICANT</div><h1>Ative a verificação em duas etapas</h1><p>No Google Authenticator, Microsoft Authenticator ou outro aplicativo TOTP, escolha adicionar uma chave manual e copie o código abaixo.</p><div class="secret-box">${esc(app.activation.secret)}</div><p class="help">Conta: briangabrielfsoares@gmail.com · Tipo: baseado em tempo · 6 dígitos.</p><div class="field"><label>Código de 6 dígitos</label><input name="totp" inputmode="numeric" maxlength="6" required></div><button class="btn" style="width:100%">FINALIZAR ATIVAÇÃO</button></form></div>`;$('#finishForm').onsubmit=async e=>{e.preventDefault();try{const j=await api('activate-finish',{method:'POST',body:{activationId:app.activation.activationId,totp:new FormData(e.target).get('totp')}});app.admin=j.admin;renderShell()}catch(err){toast(err.message)}}}
function renderLogin(){$('#adminApp').innerHTML=`<div class="auth-shell"><form class="auth-card" id="loginForm"><div class="auth-logo">ICANT</div><h1>Painel Administrativo Master</h1><p>Acesso protegido por senha, sessão segura e código 2FA.</p><div class="field"><label>E-mail</label><input type="email" name="email" value="briangabrielfsoares@gmail.com" required></div><div class="field"><label>Senha</label><input type="password" name="password" required></div><div class="field"><label>Código 2FA</label><input name="totp" inputmode="numeric" maxlength="6" required></div><button class="btn" style="width:100%">ENTRAR</button><a class="btn ghost" href="/" style="display:flex;margin-top:9px;align-items:center;justify-content:center">VER LOJA</a></form></div>`;$('#loginForm').onsubmit=async e=>{e.preventDefault();try{const j=await api('login',{method:'POST',body:Object.fromEntries(new FormData(e.target))});app.admin=j.admin;renderShell()}catch(err){toast(err.message)}}}
function renderShell(){$('#adminApp').innerHTML=`<div class="admin-shell"><aside class="sidebar" id="sidebar"><div class="sidebar-head"><div class="sidebar-brand">ICANT</div><button class="btn ghost small" id="closeSide">×</button></div><nav class="sidebar-nav">${MODULES.map(([g,items])=>`<div class="nav-group">${g}</div>${items.map(([id,icon,name])=>`<button class="nav-btn ${app.module===id?'active':''}" data-module="${id}"><span class="nav-icon">${icon}</span><span>${name}</span></button>`).join('')}`).join('')}</nav><div class="sidebar-foot"><button class="nav-btn" id="logoutBtn"><span class="nav-icon">↪</span>Sair</button></div></aside><main class="admin-main"><header class="topbar"><div class="topbar-left"><button class="mobile-nav" id="openSide">☰</button><div><h1 id="moduleTitle">Painel Master</h1><div class="help">${esc(app.admin?.name||'Administrador')} · ${esc(app.admin?.role||'')}</div></div></div><div class="topbar-actions"><a class="btn ghost small hide-mobile" href="/" target="_blank">VER LOJA</a><button class="btn small" id="quickProduct">+ PRODUTO</button></div></header><div class="content" id="content"></div></main></div>`;bindShell();navigate(app.module)}
function bindShell(){$$('[data-module]').forEach(b=>b.onclick=()=>navigate(b.dataset.module));$('#logoutBtn').onclick=async()=>{await api('logout');app.admin=null;renderLogin()};$('#quickProduct').onclick=()=>openProductEditor();$('#openSide').onclick=()=>$('#sidebar').classList.add('open');$('#closeSide').onclick=()=>$('#sidebar').classList.remove('open')}
function navigate(module){app.module=module;$$('[data-module]').forEach(b=>b.classList.toggle('active',b.dataset.module===module));$('#sidebar')?.classList.remove('open');const labels=MODULES.flatMap(x=>x[1]).find(x=>x[0]===module);$('#moduleTitle').textContent=labels?.[2]||module;({dashboard,visual,products,categories,orders,customers,marketing,drops,outfits,inventory,suppliers,media,pages,reports,integrations,settings,admins,audit}[module]||dashboard)()}
async function dashboard(){try{const j=await api('dashboard');const m=j.metrics;$('#content').innerHTML=`<div class="stats"><div class="stat"><small>Faturamento</small><strong>${money(m.revenue)}</strong></div><div class="stat"><small>Pedidos</small><strong>${m.orders}</strong></div><div class="stat"><small>Produtos ativos</small><strong>${m.activeProducts}</strong></div><div class="stat"><small>Clientes</small><strong>${m.customers}</strong></div><div class="stat"><small>Estoque baixo</small><strong>${m.lowStock}</strong></div><div class="stat"><small>Tickets abertos</small><strong>${m.openTickets}</strong></div></div><div class="grid2"><section class="panel"><div class="panel-head"><h2>Pedidos recentes</h2><button class="btn ghost small" data-go="orders">VER TODOS</button></div><div class="panel-body">${ordersTable(j.recentOrders||[])}</div></section><section class="panel"><div class="panel-head"><h2>Ações rápidas</h2></div><div class="panel-body"><div class="grid2"><button class="btn" data-quick="product">Novo produto</button><button class="btn dark" data-go="visual">Editar visual</button><button class="btn dark" data-go="marketing">Criar cupom</button><button class="btn dark" data-go="media">Enviar mídia</button></div><div class="warning" style="margin-top:15px">Integrações externas como gateway, Correios, emissão fiscal e Pixel precisam das credenciais de cada serviço. O painel já possui os módulos de configuração.</div></div></section></div>`;$$('[data-go]').forEach(b=>b.onclick=()=>navigate(b.dataset.go));$('[data-quick="product"]')?.addEventListener('click',()=>openProductEditor())}catch(e){showError(e)}}
function ordersTable(items){return items.length?`<div class="table-wrap"><table class="table"><thead><tr><th>Pedido</th><th>Cliente</th><th>Total</th><th>Status</th><th>Data</th></tr></thead><tbody>${items.map(o=>`<tr><td>${esc(o.number||o.id)}</td><td>${esc(o.customer?.name||o.name||'')}</td><td>${money(o.total)}</td><td><span class="status ${esc(o.status)}">${esc(o.status||'')}</span></td><td>${date(o.createdAt)}</td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">Nenhum pedido ainda.</div>'}
function date(v){return v?new Date(v).toLocaleString('pt-BR'):'—'}
async function visual(){try{const j=await api('settings-get');app.settings=j.settings;$('#content').innerHTML=`<div class="preview-layout"><div class="settings-list"><div class="inline" style="justify-content:space-between;margin-bottom:14px"><strong>Editor visual</strong><button class="btn small" id="saveVisual">PUBLICAR</button></div>${visualFields(app.settings)}</div><iframe class="live-frame" id="previewFrame" src="/?editor=1"></iframe></div>`;bindVisual()}catch(e){showError(e)}}
function visualFields(s){return `<div class="setting-group"><h3>Marca</h3>${input('storeName','Nome da loja',s.storeName)}${input('slogan','Slogan',s.slogan)}${input('logoText','Logo em texto',s.logoText)}${input('logoImage','Imagem da logo',s.logoImage)}${input('favicon','Favicon',s.favicon)}</div><div class="setting-group"><h3>Hero / Banner</h3>${check('hero.enabled','Exibir banner',s.hero?.enabled)}${input('hero.title','Título',s.hero?.title)}${input('hero.subtitle','Subtítulo',s.hero?.subtitle)}${input('hero.buttonText','Texto do botão',s.hero?.buttonText)}${input('hero.buttonLink','Link do botão',s.hero?.buttonLink)}${input('hero.image','Imagem de fundo',s.hero?.image)}${numberInput('hero.overlay','Escurecimento %',s.hero?.overlay)}${numberInput('hero.heightDesktop','Altura desktop',s.hero?.heightDesktop)}${numberInput('hero.heightMobile','Altura celular',s.hero?.heightMobile)}</div><div class="setting-group"><h3>Cores</h3>${colorInput('colors.background','Fundo escuro',s.colors?.background)}${colorInput('colors.surface','Fundo claro',s.colors?.surface)}${colorInput('colors.text','Texto',s.colors?.text)}${colorInput('colors.card','Cards',s.colors?.card)}${colorInput('colors.accent','Destaque',s.colors?.accent)}</div><div class="setting-group"><h3>Tipografia</h3>${input('typography.fontFamily','Fonte CSS',s.typography?.fontFamily)}${numberInput('typography.baseSize','Tamanho base',s.typography?.baseSize)}</div><div class="setting-group"><h3>Benefícios</h3>${(s.benefits||[]).map((b,i)=>input(`benefits.${i}.text`,`Benefício ${i+1}`,b.text)).join('')}</div><div class="setting-group"><h3>Barra promocional e popup</h3>${check('promoBar.enabled','Ativar barra',s.promoBar?.enabled)}${input('promoBar.text','Texto da barra',s.promoBar?.text)}${check('popup.enabled','Ativar popup',s.popup?.enabled)}${input('popup.title','Título do popup',s.popup?.title)}${textarea('popup.text','Texto do popup',s.popup?.text)}</div><div class="setting-group"><h3>Seções da home</h3><div id="sectionsEditor">${(s.homeSections||[]).sort((a,b)=>a.order-b.order).map((x,i)=>`<div class="section-row" draggable="true" data-section-index="${i}"><span class="drag">☷</span><div>${input(`homeSections.${i}.title`,'Título',x.title)}${selectInput(`homeSections.${i}.source`,'Fonte',x.source,['new','bestseller','featured','all'])}${numberInput(`homeSections.${i}.limit`,'Limite',x.limit)}</div><label class="check"><input type="checkbox" data-path="homeSections.${i}.enabled" ${x.enabled!==false?'checked':''}>Ativa</label></div>`).join('')}</div><button class="btn ghost small" id="addSection">+ SEÇÃO</button></div>`}
function input(path,label,value,type='text'){return `<div class="field"><label>${esc(label)}</label><input type="${type}" data-path="${esc(path)}" value="${esc(value??'')}"></div>`}function numberInput(path,label,value){return input(path,label,value,'number')}function textarea(path,label,value){return `<div class="field"><label>${esc(label)}</label><textarea data-path="${esc(path)}">${esc(value??'')}</textarea></div>`}function check(path,label,value){return `<label class="check"><input type="checkbox" data-path="${esc(path)}" ${value?'checked':''}>${esc(label)}</label>`}function colorInput(path,label,value){return `<div class="field"><label>${esc(label)}</label><div class="color-field"><input type="color" data-color-for="${esc(path)}" value="${esc(value||'#000000')}"><input data-path="${esc(path)}" value="${esc(value||'#000000')}"></div></div>`}function selectInput(path,label,value,opts){return `<div class="field"><label>${esc(label)}</label><select data-path="${esc(path)}">${opts.map(x=>`<option value="${esc(x)}" ${x===value?'selected':''}>${esc(x)}</option>`).join('')}</select></div>`}
function setDeep(obj,path,val){const parts=path.split('.');let o=obj;parts.forEach((p,i)=>{if(i===parts.length-1)o[p]=val;else{o[p]??=/^\d+$/.test(parts[i+1])?[]:{};o=o[p]}})}
function bindVisual(){const panel=$('.settings-list');panel.oninput=e=>{const el=e.target,path=el.dataset.path;if(!path)return;let v=el.type==='checkbox'?el.checked:el.type==='number'?Number(el.value):el.value;setDeep(app.settings,path,v);if(el.matches('[data-path^="colors."]'))document.querySelector(`[data-color-for="${CSS.escape(path)}"]`)?.setAttribute('value',v)};$$('[data-color-for]').forEach(c=>c.oninput=()=>{const p=c.dataset.colorFor;const t=document.querySelector(`[data-path="${CSS.escape(p)}"]`);t.value=c.value;t.dispatchEvent(new Event('input',{bubbles:true}))});$('#saveVisual').onclick=async()=>{try{await api('settings-save',{method:'POST',body:{settings:app.settings}});toast('Alterações publicadas');$('#previewFrame').contentWindow.location.reload()}catch(e){toast(e.message)}};$('#addSection').onclick=()=>{app.settings.homeSections.push({id:`section_${Date.now()}`,type:'products',title:'NOVA SEÇÃO',source:'all',limit:5,enabled:true,order:app.settings.homeSections.length+1});visual()};window.onmessage=e=>{if(e.origin!==location.origin||e.data?.type!=='icant-edit')return;const el=document.querySelector(`[data-path="${CSS.escape(e.data.key)}"]`);if(el){el.scrollIntoView({behavior:'smooth',block:'center'});el.focus();toast(`Editando: ${e.data.key}`)}};let drag=null;$$('[data-section-index]').forEach(row=>{row.ondragstart=()=>drag=Number(row.dataset.sectionIndex);row.ondragover=e=>e.preventDefault();row.ondrop=e=>{e.preventDefault();const to=Number(row.dataset.sectionIndex),arr=app.settings.homeSections;const [m]=arr.splice(drag,1);arr.splice(to,0,m);arr.forEach((x,i)=>x.order=i+1);visual()}})}
async function products(){try{const j=await api('list',{query:{type:'products'}});app.cache.products=j.items;$('#content').innerHTML=`<section class="panel" style="margin-top:0"><div class="panel-head"><h2>Produtos (${j.items.length})</h2><div class="toolbar"><input id="productSearch" placeholder="Buscar"><button class="btn ghost small" id="importLinkBtn">IMPORTAR LINK</button><button class="btn ghost small" id="exportProducts">EXPORTAR CSV</button><label class="btn ghost small">IMPORTAR CSV<input type="file" id="importProducts" accept=".csv" hidden></label><button class="btn small" id="newProduct">+ PRODUTO</button></div></div><div class="panel-body" id="productsTable">${productsTable(j.items)}</div></section>`;$('#newProduct').onclick=()=>openProductEditor();$('#productSearch').oninput=e=>{$('#productsTable').innerHTML=productsTable(j.items.filter(p=>`${p.name} ${p.brand} ${p.category} ${p.sku||''}`.toLowerCase().includes(e.target.value.toLowerCase())));bindProductRows()};$('#importLinkBtn').onclick=importProductLink;$('#exportProducts').onclick=()=>exportCSV(j.items);$('#importProducts').onchange=e=>importCSV(e.target.files[0]);bindProductRows()}catch(e){showError(e)}}
function productsTable(items){return items.length?`<div class="table-wrap"><table class="table"><thead><tr><th>Produto</th><th>Preço</th><th>Estoque</th><th>Categoria</th><th>Status</th><th>Ações</th></tr></thead><tbody>${items.map(p=>`<tr draggable="true" data-id="${esc(p.id)}"><td><div class="inline"><img class="thumb" src="${esc(p.images?.[0]||'')}" alt=""><div><strong>${esc(p.name)}</strong><div class="help">${esc(p.brand||'')} · ${esc(p.sku||p.variants?.[0]?.sku||'')}</div></div></div></td><td>${money(p.price)}${p.oldPrice?`<div class="help"><s>${money(p.oldPrice)}</s></div>`:''}</td><td>${Number(p.stock||0)}</td><td>${esc(p.category||'—')}</td><td><span class="status ${p.active!==false&&!p.archived?'on':'off'}">${p.archived?'ARQUIVADO':p.active!==false?'ATIVO':'INATIVO'}</span></td><td><div class="actions"><button class="btn ghost small" data-edit="${esc(p.id)}">EDITAR</button><button class="btn ghost small" data-history="${esc(p.id)}">VERSÕES</button><button class="btn ghost small" data-copy="${esc(p.id)}">DUPLICAR</button><button class="btn danger small" data-del="${esc(p.id)}">EXCLUIR</button></div></td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">Nenhum produto cadastrado.</div>'}
function bindProductRows(){$$('[data-edit]').forEach(b=>b.onclick=()=>openProductEditor(app.cache.products.find(p=>p.id===b.dataset.edit)));$$('[data-history]').forEach(b=>b.onclick=()=>showHistory('products',b.dataset.history,products));$$('[data-copy]').forEach(b=>b.onclick=async()=>{try{await api('duplicate',{method:'POST',body:{type:'products',id:b.dataset.copy}});toast('Produto duplicado');products()}catch(e){toast(e.message)}});$$('[data-del]').forEach(b=>b.onclick=()=>confirmDelete('products',b.dataset.del,products))}
function productDefaults(){return {name:'',slug:'',brand:'ICANT',description:'',price:0,oldPrice:null,cost:0,badge:'',category:'',subcategory:'',gender:'Unissex',collection:'',tags:[],images:[],video:'',active:true,archived:false,new:true,bestseller:false,featured:false,status:'draft',publishAt:'',availableUntil:'',stock:0,sold:0,rating:5,reviewCount:0,attributes:{Tamanhos:[],Cores:[]},variants:[],weight:0,dimensions:{width:0,height:0,length:0},seo:{title:'',description:''}}}
function openProductEditor(item=null){const p=structuredClone(item||productDefaults());if(item&&!p.status)p.status=p.active!==false?'published':'draft';openDrawer(item?'Editar produto':'Novo produto',`<form id="productForm"><div class="tabs"><button type="button" class="tab active" data-tab="basic">Básico</button><button type="button" class="tab" data-tab="media">Mídias</button><button type="button" class="tab" data-tab="variants">Variações</button><button type="button" class="tab" data-tab="seo">SEO</button></div><div data-pane="basic"><div class="form-grid">${inputF('name','Nome',p.name,'text','full')}${inputF('slug','URL/slug',p.slug)}${inputF('brand','Marca',p.brand)}${textareaF('description','Descrição',p.description,'full')}${inputF('price','Preço',p.price,'number')}${inputF('oldPrice','Preço antigo',p.oldPrice??'','number')}${inputF('cost','Custo',p.cost,'number')}${inputF('stock','Estoque total',p.stock,'number')}${inputF('sku','SKU principal',p.sku||'')}${inputF('badge','Selo',p.badge||'')}${inputF('category','Categoria',p.category||'')}${inputF('subcategory','Subcategoria',p.subcategory||'')}${selectF('gender','Gênero',p.gender,['Masculino','Feminino','Unissex','Infantil'])}${inputF('collection','Coleção',p.collection||'')}${selectF('status','Status de publicação',p.status||'draft',['draft','published','scheduled'])}${inputF('publishAt','Publicar em',p.publishAt||'','datetime-local')}${inputF('availableUntil','Disponível até',p.availableUntil||'','datetime-local')}${inputF('tags','Tags',arrayText(p.tags))}${inputF('sizes','Tamanhos',arrayText(p.attributes?.Tamanhos))}${inputF('colors','Cores',arrayText(p.attributes?.Cores))}${inputF('weight','Peso kg',p.weight,'number')}${inputF('dimensions','Dimensões LxAxC',`${p.dimensions?.width||0},${p.dimensions?.height||0},${p.dimensions?.length||0}`)}<div class="full permissions">${checkF('active','Produto ativo',p.active!==false)}${checkF('archived','Arquivado',p.archived)}${checkF('new','Lançamento',p.new)}${checkF('bestseller','Mais vendido',p.bestseller)}${checkF('featured','Destaque',p.featured)}</div></div></div><div data-pane="media" hidden><div class="product-upload"><label class="btn" id="productUploadLabel">ENVIAR IMAGENS<input id="productImageUpload" type="file" multiple accept="image/jpeg,image/png,image/webp,image/gif" hidden></label><span class="help" id="productUploadStatus">Selecione imagens do computador ou celular.</span></div><div id="productImagePreview" class="media-grid product-media-preview"></div>${textareaF('images','Imagens — uma URL por linha',(p.images||[]).join('\n'),'full')}${inputF('video','Vídeo',p.video||'')}<div class="help">As imagens enviadas entram automaticamente no campo acima. A primeira imagem é a principal.</div></div><div data-pane="variants" hidden><div class="warning">Cada linha deve ser um JSON de variação. Exemplo: {"attributes":{"Tamanho":"M","Cor":"Preto"},"price":159.9,"stock":5,"sku":"IC-001-M-P"}</div>${textareaF('variants','Variações — um JSON por linha',(p.variants||[]).map(v=>JSON.stringify(v)).join('\n'),'full')}</div><div data-pane="seo" hidden>${inputF('seoTitle','Título SEO',p.seo?.title||'')}${textareaF('seoDescription','Descrição SEO',p.seo?.description||'','full')}</div></form>`,async()=>{const form=$('#productForm'),fd=new FormData(form);const dims=String(fd.get('dimensions')||'').split(',').map(Number);let variants=[];try{variants=String(fd.get('variants')||'').split('\n').filter(Boolean).map(x=>JSON.parse(x))}catch{throw new Error('Existe uma variação com JSON inválido.')};const rec={...p,name:fd.get('name'),slug:fd.get('slug')||slugify(fd.get('name')),brand:fd.get('brand'),description:fd.get('description'),price:Number(fd.get('price')),oldPrice:fd.get('oldPrice')?Number(fd.get('oldPrice')):null,cost:Number(fd.get('cost')),stock:Number(fd.get('stock')),sku:fd.get('sku'),badge:fd.get('badge'),category:fd.get('category'),subcategory:fd.get('subcategory'),gender:fd.get('gender'),collection:fd.get('collection'),status:fd.get('status'),publishAt:fd.get('publishAt'),availableUntil:fd.get('availableUntil'),tags:splitList(fd.get('tags')),images:String(fd.get('images')||'').split('\n').map(x=>x.trim()).filter(Boolean),video:fd.get('video'),attributes:{Tamanhos:splitList(fd.get('sizes')),Cores:splitList(fd.get('colors'))},weight:Number(fd.get('weight')),dimensions:{width:dims[0]||0,height:dims[1]||0,length:dims[2]||0},active:fd.get('active')==='on',archived:fd.get('archived')==='on',new:fd.get('new')==='on',bestseller:fd.get('bestseller')==='on',featured:fd.get('featured')==='on',variants,seo:{title:fd.get('seoTitle'),description:fd.get('seoDescription')}};await api('save',{method:'POST',body:{type:'products',item:rec}});toast('Produto salvo');closeDrawer();products()});bindTabs();bindProductMediaUpload()}

function bindProductMediaUpload(){const picker=$('#productImageUpload'),field=$('#productForm [name="images"]'),status=$('#productUploadStatus'),preview=$('#productImagePreview');if(!picker||!field)return;const render=()=>{const urls=field.value.split('\n').map(x=>x.trim()).filter(Boolean);preview.innerHTML=urls.map((url,i)=>`<div class="media-card"><img src="${esc(url)}" alt="Imagem ${i+1}"><div><strong>${i===0?'Imagem principal':`Imagem ${i+1}`}</strong></div></div>`).join('')};field.addEventListener('input',render);render();picker.onchange=async()=>{const files=[...picker.files];if(!files.length)return;picker.disabled=true;status.textContent=`Enviando 0 de ${files.length}...`;try{for(let i=0;i<files.length;i++){status.textContent=`Enviando ${i+1} de ${files.length}: ${files[i].name}`;const item=await uploadMediaFile(files[i]);const urls=field.value.split('\n').map(x=>x.trim()).filter(Boolean);if(!urls.includes(item.url))urls.push(item.url);field.value=urls.join('\n');field.dispatchEvent(new Event('input',{bubbles:true}));toast(`${files[i].name} enviado`)}status.textContent=`${files.length} imagem(ns) enviada(s) com sucesso.`}catch(e){status.textContent=`Falha no envio: ${e.message}`;toast(e.message)}finally{picker.disabled=false;picker.value=''}}}
function inputF(name,label,value,type='text',cls=''){return `<div class="field ${cls}"><label>${esc(label)}</label><input name="${esc(name)}" type="${type}" value="${esc(value??'')}"></div>`}function textareaF(name,label,value,cls=''){return `<div class="field ${cls}"><label>${esc(label)}</label><textarea name="${esc(name)}">${esc(value??'')}</textarea></div>`}function selectF(name,label,value,opts){return `<div class="field"><label>${esc(label)}</label><select name="${esc(name)}">${opts.map(x=>`<option ${x===value?'selected':''}>${esc(x)}</option>`).join('')}</select></div>`}function checkF(name,label,value){return `<label class="check"><input type="checkbox" name="${esc(name)}" ${value?'checked':''}>${esc(label)}</label>`}function splitList(v){return String(v||'').split(',').map(x=>x.trim()).filter(Boolean)}function arrayText(v){return Array.isArray(v)?v.join(', '):''}function slugify(v){return String(v||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'')}
function bindTabs(){$$('[data-tab]').forEach(b=>b.onclick=()=>{$$('[data-tab]').forEach(x=>x.classList.toggle('active',x===b));$$('[data-pane]').forEach(p=>p.hidden=p.dataset.pane!==b.dataset.tab)})}
async function categories(){genericResource(RESOURCE_MAP.categories)}async function customers(){genericResource(RESOURCE_MAP.customers)}async function drops(){genericResource(RESOURCE_MAP.drops)}async function outfits(){genericResource(RESOURCE_MAP.outfits)}async function suppliers(){genericResource(RESOURCE_MAP.suppliers)}async function pages(){genericResource(RESOURCE_MAP.pages)}async function integrations(){genericResource(RESOURCE_MAP.integrations)}
async function genericResource(schema){try{const j=await api('list',{query:{type:schema.type}});app.cache[schema.type]=j.items;$('#content').innerHTML=`<section class="panel" style="margin-top:0"><div class="panel-head"><h2>${esc(schema.title)} (${j.items.length})</h2><div class="toolbar"><input id="genericSearch" placeholder="Buscar"><button class="btn small" id="newGeneric">+ NOVO</button></div></div><div class="panel-body" id="genericTable">${genericTable(j.items,schema)}</div></section>`;$('#newGeneric').onclick=()=>openGenericEditor(schema);$('#genericSearch').oninput=e=>{$('#genericTable').innerHTML=genericTable(j.items.filter(x=>JSON.stringify(x).toLowerCase().includes(e.target.value.toLowerCase())),schema);bindGeneric(schema)};bindGeneric(schema)}catch(e){showError(e)}}
function genericTable(items,schema){return items.length?`<div class="table-wrap"><table class="table"><thead><tr><th>Nome</th><th>Status</th><th>Atualizado</th><th>Ações</th></tr></thead><tbody>${items.map(x=>`<tr><td><strong>${esc(x.name||x.title||x.code||x.email||x.id)}</strong><div class="help">${esc(x.description||x.slug||x.type||'')}</div></td><td><span class="status ${(x.active||x.status==='published')?'on':''}">${esc(x.status||((x.active||x.enabled)?'ATIVO':'INATIVO'))}</span></td><td>${date(x.updatedAt)}</td><td><div class="actions"><button class="btn ghost small" data-edit-g="${esc(x.id)}">EDITAR</button><button class="btn ghost small" data-copy-g="${esc(x.id)}">DUPLICAR</button><button class="btn danger small" data-del-g="${esc(x.id)}">EXCLUIR</button></div></td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">Nenhum item cadastrado.</div>'}
function bindGeneric(schema){$$('[data-edit-g]').forEach(b=>b.onclick=()=>openGenericEditor(schema,app.cache[schema.type].find(x=>x.id===b.dataset.editG)));$$('[data-copy-g]').forEach(b=>b.onclick=async()=>{await api('duplicate',{method:'POST',body:{type:schema.type,id:b.dataset.copyG}});toast('Item duplicado');genericResource(schema)});$$('[data-del-g]').forEach(b=>b.onclick=()=>confirmDelete(schema.type,b.dataset.delG,()=>genericResource(schema)))}
function openGenericEditor(schema,item={}){openDrawer(`${item.id?'Editar':'Novo'} — ${schema.title}`,`<form id="genericForm"><div class="form-grid">${schema.fields.map(([name,label,type])=>genericField(name,label,type,item[name])).join('')}</div></form>`,async()=>{const fd=new FormData($('#genericForm')),rec={...item};for(const [name,,type] of schema.fields){let v=fd.get(name);if(type==='checkbox')v=v==='on';else if(type==='number')v=Number(v)||0;else if(type==='tags')v=splitList(v);else if(type==='json'){try{v=v?JSON.parse(v):{}}catch{throw new Error(`JSON inválido em ${name}`)}}rec[name]=v}if(rec.name&&!rec.slug)rec.slug=slugify(rec.name);await api('save',{method:'POST',body:{type:schema.type,item:rec}});toast('Item salvo');closeDrawer();genericResource(schema)})}
function genericField(name,label,type,value){if(type==='textarea')return textareaF(name,label,value,'full');if(type==='checkbox')return `<div class="field full">${checkF(name,label,!!value)}</div>`;if(type==='tags')return inputF(name,label,arrayText(value),'text','full');if(type==='json')return `<div class="field full"><label>${esc(label)}</label><textarea class="json-area" name="${esc(name)}">${esc(JSON.stringify(value||{},null,2))}</textarea></div>`;if(type.startsWith('select:'))return selectF(name,label,value,type.split(':')[1].split(','));return inputF(name,label,value,type)}
async function orders(){try{const j=await api('list',{query:{type:'orders'}});app.cache.orders=j.items;$('#content').innerHTML=`<section class="panel" style="margin-top:0"><div class="panel-head"><h2>Pedidos (${j.items.length})</h2><div class="toolbar"><select id="orderFilter"><option value="">Todos</option><option>pending_payment</option><option>paid</option><option>processing</option><option>shipped</option><option>delivered</option><option>cancelled</option></select><button class="btn ghost small" id="exportOrders">EXPORTAR</button></div></div><div class="panel-body" id="ordersBox">${orderRows(j.items)}</div></section>`;$('#orderFilter').onchange=e=>$('#ordersBox').innerHTML=orderRows(j.items.filter(x=>!e.target.value||x.status===e.target.value));$('#exportOrders').onclick=()=>download(`pedidos-${Date.now()}.json`,JSON.stringify(j.items,null,2),'application/json');bindOrderRows()}catch(e){showError(e)}}
function orderRows(items){return items.length?`<div class="table-wrap"><table class="table"><thead><tr><th>Pedido</th><th>Cliente</th><th>Itens</th><th>Total</th><th>Status</th><th>Ações</th></tr></thead><tbody>${items.map(o=>`<tr><td><strong>${esc(o.number||o.id)}</strong><div class="help">${date(o.createdAt)}</div></td><td>${esc(o.customer?.name||'')}<div class="help">${esc(o.customer?.phone||'')}</div></td><td>${(o.items||[]).reduce((s,x)=>s+Number(x.qty||0),0)}</td><td>${money(o.total)}</td><td><span class="status ${esc(o.status)}">${esc(o.status)}</span></td><td><button class="btn ghost small" data-order="${esc(o.id)}">ABRIR</button></td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">Nenhum pedido.</div>'}
function bindOrderRows(){$$('[data-order]').forEach(b=>b.onclick=()=>openOrder(app.cache.orders.find(x=>x.id===b.dataset.order)))}
function openOrder(o){openDrawer(`Pedido ${o.number}`,`<div class="grid2"><div class="panel-body"><h3>Cliente</h3><p>${esc(o.customer?.name)}<br>${esc(o.customer?.cpf)}<br>${esc(o.customer?.phone)}<br>${esc(o.customer?.email||'')}</p></div><div class="panel-body"><h3>Entrega</h3><p>${esc(o.shipping?.street)}, ${esc(o.shipping?.number)}<br>${esc(o.shipping?.district)} — ${esc(o.shipping?.city)}/${esc(o.shipping?.state)}<br>CEP ${esc(o.shipping?.cep)}</p></div></div><div class="panel-body"><h3>Produtos</h3>${(o.items||[]).map(i=>`<div class="inline" style="justify-content:space-between;border-bottom:1px solid #222;padding:10px 0"><span>${i.qty}x ${esc(i.name)}<div class="help">${esc(JSON.stringify(i.attributes||{}))}</div></span><strong>${money(i.total)}</strong></div>`).join('')}<div style="margin-top:14px;text-align:right"><p>Subtotal: ${money(o.subtotal)}</p><p>Desconto: ${money(o.discount)}</p><p>Frete: ${money(o.shippingCost)}</p><h2>Total: ${money(o.total)}</h2></div></div><form id="orderForm"><div class="form-grid">${selectF('status','Status',o.status,['pending_payment','paid','processing','shipped','delivered','cancelled','refunded','exchange'])}${selectF('paymentStatus','Pagamento',o.paymentStatus||'pending',['pending','approved','rejected','refunded'])}${inputF('tracking','Rastreio',o.tracking||'')}${textareaF('adminNotes','Observações internas',o.adminNotes||'','full')}</div></form>`,async()=>{const d=Object.fromEntries(new FormData($('#orderForm')));await api('save',{method:'POST',body:{type:'orders',item:{...o,...d}}});toast('Pedido atualizado');closeDrawer();orders()})}
async function marketing(){const schemas=[RESOURCE_MAP.coupons,RESOURCE_MAP.campaigns,RESOURCE_MAP.testimonials,RESOURCE_MAP.reviews];$('#content').innerHTML=`<div class="grid2">${schemas.map(s=>`<section class="panel" style="margin-top:0"><div class="panel-head"><h2>${s.title}</h2><button class="btn small" data-marketing="${s.type}">GERENCIAR</button></div><div class="panel-body"><p class="help">Crie, edite, publique, duplique e exclua itens deste módulo.</p></div></section>`).join('')}</div>`;$$('[data-marketing]').forEach(b=>b.onclick=()=>genericResource(schemas.find(x=>x.type===b.dataset.marketing)))}
async function inventory(){try{const j=await api('list',{query:{type:'products'}});app.cache.products=j.items;const low=j.items.filter(p=>Number(p.stock||0)<=3);$('#content').innerHTML=`<div class="stats"><div class="stat"><small>Itens cadastrados</small><strong>${j.items.length}</strong></div><div class="stat"><small>Unidades totais</small><strong>${j.items.reduce((s,p)=>s+Number(p.stock||0),0)}</strong></div><div class="stat"><small>Estoque baixo</small><strong>${low.length}</strong></div></div><section class="panel"><div class="panel-head"><h2>Ajuste rápido de estoque</h2></div><div class="panel-body"><div class="table-wrap"><table class="table"><thead><tr><th>Produto</th><th>Estoque</th><th>Ajuste</th></tr></thead><tbody>${j.items.map(p=>`<tr><td>${esc(p.name)}</td><td>${p.stock||0}</td><td><div class="inline"><input type="number" value="${p.stock||0}" data-stock="${esc(p.id)}" style="width:90px;background:#080808;border:1px solid #333;color:#fff;padding:8px"><button class="btn small" data-save-stock="${esc(p.id)}">SALVAR</button></div></td></tr>`).join('')}</tbody></table></div></div></section>`;$$('[data-save-stock]').forEach(b=>b.onclick=async()=>{const p=j.items.find(x=>x.id===b.dataset.saveStock),v=Number(document.querySelector(`[data-stock="${CSS.escape(p.id)}"]`).value);await api('save',{method:'POST',body:{type:'products',item:{...p,stock:v}}});toast('Estoque atualizado')})}catch(e){showError(e)}}
async function media(){try{const j=await api('list',{query:{type:'media'}});app.cache.media=j.items.filter(x=>!x.deleted);$('#content').innerHTML=`<section class="panel" style="margin-top:0"><div class="panel-head"><h2>Biblioteca de mídias</h2><label class="btn small">ENVIAR ARQUIVOS<input id="mediaUpload" type="file" multiple accept="image/*,video/mp4,application/pdf" hidden></label></div><div class="panel-body"><div class="media-grid">${app.cache.media.length?app.cache.media.map(m=>`<div class="media-card">${m.mime?.startsWith('image/')?`<img src="${esc(m.url)}" alt="${esc(m.alt||'')}">`:'<div style="aspect-ratio:1;display:grid;place-items:center;font-size:30px">▧</div>'}<div><strong>${esc(m.name)}</strong><p class="help">${Math.round((m.size||0)/1024)} KB</p><button class="btn ghost small" data-copy-url="${esc(m.url)}">COPIAR URL</button></div></div>`).join(''):'<div class="empty">Nenhum arquivo enviado.</div>'}</div></div></section>`;$('#mediaUpload').onchange=e=>uploadMedia([...e.target.files]);$$('[data-copy-url]').forEach(b=>b.onclick=()=>navigator.clipboard.writeText(location.origin+b.dataset.copyUrl).then(()=>toast('URL copiada')))}catch(e){showError(e)}}
async function uploadMediaFile(file){const prepared=await prepareFile(file);const res=await fetch(M,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({name:file.name,mime:prepared.mime,dataBase64:prepared.data,alt:file.name.replace(/\.[^.]+$/,'')})});const j=await res.json();if(!res.ok||!j.ok)throw new Error(j.error||'Não foi possível enviar a imagem.');return j.item}
async function uploadMedia(files){for(const file of files){try{await uploadMediaFile(file);toast(`${file.name} enviado`)}catch(e){toast(`${file.name}: ${e.message}`)}}media()}
function prepareFile(file){if(file.type.startsWith('image/')&&!file.type.includes('gif')&&!file.type.includes('svg'))return compressImage(file);return fileToBase64(file).then(data=>({data,mime:file.type}))}function fileToBase64(file){return new Promise((res,rej)=>{const r=new FileReader;r.onload=()=>res(String(r.result).split(',')[1]);r.onerror=rej;r.readAsDataURL(file)})}function compressImage(file){return new Promise((res,rej)=>{const img=new Image,reader=new FileReader;reader.onload=()=>img.src=reader.result;reader.onerror=rej;img.onload=()=>{const max=1800,scale=Math.min(1,max/Math.max(img.width,img.height)),c=document.createElement('canvas');c.width=Math.round(img.width*scale);c.height=Math.round(img.height*scale);c.getContext('2d').drawImage(img,0,0,c.width,c.height);const mime='image/webp';res({data:c.toDataURL(mime,.84).split(',')[1],mime})};reader.readAsDataURL(file)})}
async function reports(){try{const [ordersJ,productsJ,customersJ]=await Promise.all([api('list',{query:{type:'orders'}}),api('list',{query:{type:'products'}}),api('list',{query:{type:'customers'}})]);const orders=ordersJ.items,paid=orders.filter(o=>['paid','processing','shipped','delivered'].includes(o.status)),rev=paid.reduce((s,o)=>s+Number(o.total||0),0),ticket=paid.length?rev/paid.length:0,profit=paid.reduce((s,o)=>s+(o.items||[]).reduce((a,i)=>{const p=productsJ.items.find(x=>x.id===i.productId);return a+(i.price-Number(p?.cost||0))*i.qty},0),0);const months=[...Array(6)].map((_,i)=>{const d=new Date;d.setMonth(d.getMonth()-(5-i));return {key:`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`,label:d.toLocaleDateString('pt-BR',{month:'short'})}});const vals=months.map(m=>paid.filter(o=>String(o.createdAt).startsWith(m.key)).reduce((s,o)=>s+Number(o.total||0),0)),max=Math.max(...vals,1);$('#content').innerHTML=`<div class="stats"><div class="stat"><small>Receita</small><strong>${money(rev)}</strong></div><div class="stat"><small>Lucro estimado</small><strong>${money(profit)}</strong></div><div class="stat"><small>Ticket médio</small><strong>${money(ticket)}</strong></div><div class="stat"><small>Clientes</small><strong>${customersJ.items.length}</strong></div><div class="stat"><small>Produtos</small><strong>${productsJ.items.length}</strong></div><div class="stat"><small>Conversão</small><strong>—</strong></div></div><div class="grid2"><section class="panel"><div class="panel-head"><h2>Faturamento — 6 meses</h2></div><div class="panel-body"><div class="chart-bars">${vals.map((v,i)=>`<div class="bar" style="height:${Math.max(2,v/max*100)}%" title="${money(v)}"><span>${months[i].label}</span></div>`).join('')}</div></div></section><section class="panel"><div class="panel-head"><h2>Exportações</h2></div><div class="panel-body"><button class="btn" id="exportReport">EXPORTAR RELATÓRIO JSON</button><p class="help">Inclui métricas, pedidos, clientes e produtos para análise externa.</p></div></section></div>`;$('#exportReport').onclick=()=>download(`relatorio-${Date.now()}.json`,JSON.stringify({generatedAt:new Date().toISOString(),metrics:{revenue:rev,profit,ticket},orders,customers:customersJ.items,products:productsJ.items},null,2),'application/json')}catch(e){showError(e)}}
async function settings(){try{const j=await api('settings-get');app.settings=j.settings;$('#content').innerHTML=`<div class="grid2"><section class="panel" style="margin-top:0"><div class="panel-head"><h2>Comércio, frete e contato</h2></div><div class="panel-body"><form id="settingsForm"><div class="form-grid">${inputF('whatsapp','WhatsApp',app.settings.contact?.whatsapp)}${inputF('email','E-mail',app.settings.contact?.email,'email')}${inputF('instagram','Instagram',app.settings.contact?.instagram)}${inputF('tiktok','TikTok',app.settings.contact?.tiktok)}${inputF('address','Endereço',app.settings.contact?.address,'text','full')}${inputF('freeShippingAt','Frete grátis acima de',app.settings.commerce?.freeShippingAt,'number')}${inputF('defaultShipping','Frete padrão',app.settings.commerce?.defaultShipping,'number')}${checkF('exchangeEnabled','Trocas ativadas',app.settings.commerce?.exchangeEnabled)}${inputF('exchangeDays','Prazo de troca em dias',app.settings.commerce?.exchangeDays??'','number')}${checkF('blockOutOfStock','Bloquear sem estoque',app.settings.commerce?.blockOutOfStock)}${inputF('lowStockThreshold','Alerta de estoque baixo',app.settings.commerce?.lowStockThreshold,'number')}${textareaF('exchangePolicy','Política de troca',app.settings.legal?.exchange,'full')}${checkF('maintenance','Modo manutenção',app.settings.maintenance?.enabled)}${textareaF('maintenanceMessage','Mensagem de manutenção',app.settings.maintenance?.message,'full')}</div><button class="btn" style="margin-top:12px">SALVAR CONFIGURAÇÕES</button></form></div></section><section class="panel" style="margin-top:0"><div class="panel-head"><h2>Backup e segurança</h2></div><div class="panel-body"><button class="btn" id="backupBtn">BAIXAR BACKUP</button><label class="btn ghost" style="display:inline-flex;align-items:center;margin-left:5px">RESTAURAR<input id="restoreFile" type="file" accept=".json" hidden></label><button class="btn ghost" id="passwordBtn" style="margin-top:10px">ALTERAR MINHA SENHA</button><button class="btn ghost" id="advancedJsonBtn" style="margin-top:10px;margin-left:5px">CONFIGURAÇÃO AVANÇADA JSON</button><div class="danger-box" style="margin-top:15px">A restauração substitui conteúdos com os mesmos IDs. Faça backup antes. Chaves privadas, hash de senha e segredo 2FA não são exportados.</div></div></section></div><div class="grid3"><section class="panel"><div class="panel-head"><h2>Frete avançado</h2><button class="btn small" data-resource="shipping">GERENCIAR</button></div></section><section class="panel"><div class="panel-head"><h2>Pagamentos</h2><button class="btn small" data-resource="payments">GERENCIAR</button></div></section><section class="panel"><div class="panel-head"><h2>Integrações</h2><button class="btn small" data-resource="integrations">GERENCIAR</button></div></section></div>`;$('#settingsForm').onsubmit=saveSettingsForm;$('#backupBtn').onclick=backup;$('#restoreFile').onchange=e=>restore(e.target.files[0]);$('#passwordBtn').onclick=changePassword;$('#advancedJsonBtn').onclick=advancedSettingsJson;$$('[data-resource]').forEach(b=>b.onclick=()=>genericResource(RESOURCE_MAP[b.dataset.resource]))}catch(e){showError(e)}}
async function saveSettingsForm(e){e.preventDefault();const f=new FormData(e.target),s=app.settings;s.contact={...s.contact,whatsapp:f.get('whatsapp'),email:f.get('email'),instagram:f.get('instagram'),tiktok:f.get('tiktok'),address:f.get('address')};s.commerce={...s.commerce,freeShippingAt:Number(f.get('freeShippingAt')),defaultShipping:Number(f.get('defaultShipping')),exchangeEnabled:f.get('exchangeEnabled')==='on',exchangeDays:f.get('exchangeDays')?Number(f.get('exchangeDays')):null,blockOutOfStock:f.get('blockOutOfStock')==='on',lowStockThreshold:Number(f.get('lowStockThreshold'))};s.legal={...s.legal,exchange:f.get('exchangePolicy')};s.maintenance={...s.maintenance,enabled:f.get('maintenance')==='on',message:f.get('maintenanceMessage')};await api('settings-save',{method:'POST',body:{settings:s}});toast('Configurações salvas')}
async function backup(){const j=await api('backup');download(`icant-backup-${new Date().toISOString().slice(0,10)}.json`,JSON.stringify(j.backup,null,2),'application/json')}
async function restore(file){if(!file)return;const text=await file.text();let backupData;try{backupData=JSON.parse(text)}catch{return toast('Backup inválido')};const confirmText=prompt('Digite RESTAURAR para confirmar:');if(confirmText!=='RESTAURAR')return;await api('restore',{method:'POST',body:{backup:backupData,confirm:'RESTAURAR'}});toast('Backup restaurado')}
function changePassword(){openDrawer('Alterar senha',`<form id="passForm">${inputF('currentPassword','Senha atual','','password')}${inputF('newPassword','Nova senha (mínimo 10 caracteres)','','password')}${inputF('confirmPassword','Repita a nova senha','','password')}</form>`,async()=>{const d=Object.fromEntries(new FormData($('#passForm')));if(d.newPassword!==d.confirmPassword)throw new Error('As senhas não conferem.');await api('change-password',{method:'POST',body:d});toast('Senha alterada. Entre novamente.');closeDrawer();renderLogin()})}
async function admins(){try{const j=await api('admins-list');app.cache.admins=j.items;$('#content').innerHTML=`<section class="panel" style="margin-top:0"><div class="panel-head"><h2>Administradores</h2><button class="btn small" id="newAdmin">+ ADMIN</button></div><div class="panel-body"><div class="table-wrap"><table class="table"><thead><tr><th>Nome</th><th>Função</th><th>Status</th><th>Último acesso</th><th>Ação</th></tr></thead><tbody>${j.items.map(a=>`<tr><td><strong>${esc(a.name)}</strong><div class="help">${esc(a.email)}</div></td><td>${esc(a.role)}</td><td><span class="status ${a.disabled?'off':'on'}">${a.disabled?'DESATIVADO':'ATIVO'}</span></td><td>${date(a.lastLoginAt)}</td><td>${a.id!==app.admin.id?`<button class="btn ${a.disabled?'ok':'danger'} small" data-toggle-admin="${esc(a.id)}" data-disabled="${a.disabled?'0':'1'}">${a.disabled?'ATIVAR':'DESATIVAR'}</button>`:'Conta atual'}</td></tr>`).join('')}</tbody></table></div></div></section>`;$('#newAdmin').onclick=newAdmin;$$('[data-toggle-admin]').forEach(b=>b.onclick=async()=>{await api('admins-toggle',{method:'POST',body:{id:b.dataset.toggleAdmin,disabled:b.dataset.disabled==='1'}});admins()})}catch(e){showError(e)}}
function newAdmin(){const perms=['dashboard:read','products:*','categories:*','orders:*','customers:*','marketing:*','drops:*','outfits:*','inventory:*','suppliers:*','media:*','pages:*','reports:read','integrations:*','settings:read','audit:read'];openDrawer('Novo administrador',`<form id="adminForm"><div class="form-grid">${inputF('name','Nome','')}${inputF('email','E-mail','','email')}${inputF('password','Senha temporária','','password')}${selectF('role','Função','manager',['manager','editor','support','stock'])}<div class="field full"><label>Permissões</label><div class="permissions">${perms.map(p=>`<label class="check"><input type="checkbox" name="perm" value="${esc(p)}" checked>${esc(p)}</label>`).join('')}</div></div></div></form>`,async()=>{const f=new FormData($('#adminForm')),j=await api('admins-create',{method:'POST',body:{name:f.get('name'),email:f.get('email'),password:f.get('password'),role:f.get('role'),permissions:f.getAll('perm')}});closeDrawer();openDrawer('2FA do novo administrador',`<div class="success">Administrador criado. Entregue esta chave apenas para a pessoa autorizada.</div><div class="secret-box" style="margin-top:12px">${esc(j.secret)}</div><p class="help">O novo administrador deve adicionar a chave no aplicativo autenticador antes de entrar.</p>`,()=>{closeDrawer();admins()},'CONCLUIR')})}
async function audit(){try{const j=await api('audit',{query:{limit:500}});$('#content').innerHTML=`<section class="panel" style="margin-top:0"><div class="panel-head"><h2>Logs de auditoria</h2><button class="btn ghost small" id="exportAudit">EXPORTAR</button></div><div class="panel-body">${j.items.length?j.items.map(x=>`<div class="audit-line"><span>${date(x.at)}</span><span>${esc(x.actorEmail)}</span><span>${esc(x.action)}</span><span>${esc(x.module)} / ${esc(x.target)} — ${esc(JSON.stringify(x.details||{}))}</span></div>`).join(''):'<div class="empty">Sem registros.</div>'}</div></section>`;$('#exportAudit').onclick=()=>download(`auditoria-${Date.now()}.json`,JSON.stringify(j.items,null,2),'application/json')}catch(e){showError(e)}}
function openDrawer(title,html,onSave,saveText='SALVAR'){document.body.insertAdjacentHTML('beforeend',`<div class="drawer-back" id="editBack"></div><aside class="edit-drawer" id="editDrawer"><div class="drawer-head"><h2>${esc(title)}</h2><button class="btn ghost small" data-close-drawer>×</button></div><div class="drawer-body">${html}</div><div class="drawer-foot"><button class="btn ghost" data-close-drawer>CANCELAR</button><button class="btn" id="drawerSave">${saveText}</button></div></aside>`);$('#editBack').onclick=closeDrawer;$$('[data-close-drawer]').forEach(b=>b.onclick=closeDrawer);$('#drawerSave').onclick=async()=>{const b=$('#drawerSave');b.disabled=true;try{await onSave()}catch(e){toast(e.message);b.disabled=false}}}
function closeDrawer(){$('#editBack')?.remove();$('#editDrawer')?.remove()}
function confirmDelete(type,id,after){const word=prompt('Digite EXCLUIR para apagar definitivamente:');if(word!=='EXCLUIR')return;api('delete',{method:'POST',body:{type,id,confirm:'EXCLUIR'}}).then(()=>{toast('Excluído');after()}).catch(e=>toast(e.message))}

async function importProductLink(){
  const url=prompt('Cole o link público do produto da Shopee, RedDrop ou outro anúncio:');if(!url)return;
  try{const j=await api('import-link',{method:'POST',body:{url}});toast(j.diagnostic||'Dados encontrados');openProductEditor({...productDefaults(),...j.item})}catch(e){alert(`Não foi possível importar automaticamente.\n\nDiagnóstico: ${e.message}\n\nO anúncio pode bloquear robôs ou não expor dados públicos. Você ainda pode cadastrar manualmente.`)}
}
async function showHistory(type,id,after){
  try{const j=await api('history',{query:{type,id}});openDrawer('Histórico de versões',j.items.length?`<div>${j.items.map((v,i)=>`<div style="border-bottom:1px solid #272727;padding:12px 0"><strong>${date(v.versionedAt||v.updatedAt)}</strong><div class="help">${esc(v.name||v.title||v.id)}</div><button class="btn ghost small" data-restore-version="${i}">RESTAURAR ESTA VERSÃO</button></div>`).join('')}</div>`:'<div class="empty">Ainda não existem versões anteriores.</div>',async()=>closeDrawer(),'FECHAR');$$('[data-restore-version]').forEach(b=>b.onclick=async()=>{if(prompt('Digite RESTAURAR para confirmar:')!=='RESTAURAR')return;const v=j.items[Number(b.dataset.restoreVersion)];const key=String(v.versionedAt?new Date(v.versionedAt).getTime():'').padStart(16,'0');let found='';try{const hist=await api('history',{query:{type,id}});const target=hist.items[Number(b.dataset.restoreVersion)];if(!target)throw new Error('Versão não encontrada');await api('save',{method:'POST',body:{type,item:{...target,versionedAt:undefined}}});toast('Versão restaurada');closeDrawer();after()}catch(e){toast(e.message)}})}catch(e){toast(e.message)}
}
function advancedSettingsJson(){openDrawer('Configuração avançada',`<div class="warning">Edite apenas se souber o que está fazendo. Este JSON controla identidade, conteúdo, comércio, aplicativo, manutenção e configurações públicas.</div><form id="advancedForm"><div class="field"><label>Configuração completa</label><textarea class="json-area" name="json" style="min-height:55vh">${esc(JSON.stringify(app.settings,null,2))}</textarea></div></form>`,async()=>{let parsed;try{parsed=JSON.parse(new FormData($('#advancedForm')).get('json'))}catch{throw new Error('JSON inválido.')};await api('settings-save',{method:'POST',body:{settings:parsed}});app.settings=parsed;toast('Configuração avançada publicada');closeDrawer()})}
function exportCSV(items){const fields=['name','slug','brand','description','price','oldPrice','cost','stock','sku','badge','category','subcategory','gender','collection','active'];const lines=[fields.join(';'),...items.map(x=>fields.map(f=>`"${String(x[f]??'').replace(/"/g,'""')}"`).join(';'))];download(`produtos-${Date.now()}.csv`,lines.join('\n'),'text/csv;charset=utf-8')}
async function importCSV(file){if(!file)return;const rows=parseCSV(await file.text());if(rows.length<2)return toast('CSV vazio');const headers=rows[0];let count=0;for(const row of rows.slice(1)){const p=productDefaults();headers.forEach((h,i)=>p[h]=row[i]);['price','oldPrice','cost','stock'].forEach(k=>p[k]=Number(p[k])||0);p.active=String(p.active).toLowerCase()!=='false';p.slug=p.slug||slugify(p.name);await api('save',{method:'POST',body:{type:'products',item:p}});count++}toast(`${count} produtos importados`);products()}
function parseCSV(t){const rows=[];let row=[],cell='',q=false;for(let i=0;i<t.length;i++){const c=t[i],n=t[i+1];if(c==='"'&&q&&n==='"'){cell+='"';i++}else if(c==='"')q=!q;else if(c===';'&&!q){row.push(cell);cell=''}else if((c==='\n'||c==='\r')&&!q){if(c==='\r'&&n==='\n')i++;row.push(cell);if(row.some(x=>x!==''))rows.push(row);row=[];cell=''}else cell+=c}row.push(cell);if(row.some(x=>x!==''))rows.push(row);return rows}
function download(name,data,type){const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([data],{type}));a.download=name;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000)}
function showError(e){$('#content').innerHTML=`<div class="danger-box">${esc(e.message)}</div>`}
boot();
